package com.google.gson.stream;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Writer;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import com.google.gson.stream.JsonWriter;

class JsonWriterOpenTest {

  private JsonWriter jsonWriter;
  private Writer mockWriter;

  @BeforeEach
  public void setUp() {
    mockWriter = mock(Writer.class);
    jsonWriter = new JsonWriter(mockWriter);
  }

  @Test
  public void testOpen_withEmptyArray() throws Throwable {
    int emptyArray = 1;
    char openBracket = '[';

    JsonWriter result = invokeOpen(jsonWriter, emptyArray, openBracket);

    assertSame(jsonWriter, result);
    verify(mockWriter).write(openBracket);
  }

  @Test
  public void testOpen_withEmptyObject() throws Throwable {
    int emptyObject = 3;
    char openBracket = '{';

    JsonWriter result = invokeOpen(jsonWriter, emptyObject, openBracket);

    assertSame(jsonWriter, result);
    verify(mockWriter).write(openBracket);
  }

  @Test
  public void testOpen_beforeValueThrowsIOException() throws Throwable {
    JsonWriter spyWriter = spy(jsonWriter);

    // Use reflection to replace the private beforeValue method with a proxy that throws IOException
    Method beforeValueMethod = JsonWriter.class.getDeclaredMethod("beforeValue");
    beforeValueMethod.setAccessible(true);

    // Create a proxy method that throws IOException when beforeValue is called
    // Since we can't replace the method body, we instead use Mockito's doAnswer on the spy's open method,
    // but open is also private, so we invoke open method and catch thrown IOException manually.

    // So we invoke open via reflection on spyWriter, expecting IOException from beforeValue
    Method openMethod = JsonWriter.class.getDeclaredMethod("open", int.class, char.class);
    openMethod.setAccessible(true);

    IOException thrown = assertThrows(IOException.class, () -> {
      try {
        openMethod.invoke(new JsonWriterWithBeforeValueException(mockWriter), 1, '[');
      } catch (InvocationTargetException e) {
        Throwable cause = e.getCause();
        if (cause instanceof IOException) {
          throw cause;
        } else {
          throw e;
        }
      }
    });

    assertEquals("beforeValue error", thrown.getMessage());
  }

  private static class JsonWriterWithBeforeValueException extends JsonWriter {
    JsonWriterWithBeforeValueException(Writer out) {
      super(out);
    }

    @Override
    protected void beforeValue() throws IOException {
      throw new IOException("beforeValue error");
    }
  }

  private JsonWriter invokeOpen(JsonWriter writer, int empty, char openBracket) throws Throwable {
    Method openMethod = JsonWriter.class.getDeclaredMethod("open", int.class, char.class);
    openMethod.setAccessible(true);
    try {
      return (JsonWriter) openMethod.invoke(writer, empty, openBracket);
    } catch (InvocationTargetException e) {
      throw e.getCause();
    }
  }
}
